#include <stdio.h>

struct Employee {
    char name[50];
    int employee_id;
    float salary;
};

int main() {
    struct Employee emp;

    // Taking input
    fgets(emp.name, sizeof(emp.name), stdin);        // Read full name including spaces
    scanf("%d", &emp.employee_id);
    scanf("%f", &emp.salary);

    // Display output
    printf("Name: %s", emp.name);     // No extra newline needed, fgets keeps '\n'
    printf("ID: %d\n", emp.employee_id);
    printf("Salary: %.2f\n", emp.salary);

    return 0;
}
